############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "contextFiniteSolutionSets.pl", "contextForm.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("FiniteSolutionSets"); $solution = Formula("{2}");
############################################################ # Body ############################################################
BEGIN_PGML Solve for [`x`] in [`5-2x=5x-9\text{.}`]
[_]{$solution}{5}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION
[```\newcommand{\nextoperation}[1]{\mathord{\boxed{#1}}}\newcommand{\subtractright}[1]{{\highlight{{{}-#1}}}}\newcommand{\divideunder}[2]{\frac{#1}{{\highlight{{#2}}}}}\newcommand{\amp}{&} \begin{aligned} 5-2x\amp=\nextoperation{5x}-9\\ 5-2x\subtractright{5x}\amp=5x-9\subtractright{5x}\\ \nextoperation{5}-7x\amp=-9\\ 5-7x\subtractright{5}\amp=-9\subtractright{5}\\ -7x\amp=-14\\ \divideunder{-7x}{-7}\amp=\divideunder{-14}{-7}\\ x\amp=2 \end{aligned} ```]
Checking the solution [`2\text{:}`]
[```\newcommand{\substitute}[1]{{\color{blue}{{#1}}}}\newcommand{\confirm}[1]{\stackrel{\checkmark}{#1}}\newcommand{\wonder}[1]{\stackrel{\text{?}}{#1}}\newcommand{\amp}{&} \begin{aligned} 5-2x\amp=5x-9\\ 5-2(\substitute{2})\amp\wonder{=}5(\substitute{2})-9\\ 5-4\amp\wonder{=}10-9\\ 1\amp\confirm{=}1 \end{aligned} ```]
Therefore the solution is [`2`] and the solution set is [`\{2\}\text{.}`]
END_PGML_SOLUTION
